var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>시설 내 인원에게 안내드립니다. 현재, LAKE - 13에서 잔해 격리에 실패했습니다.</color>","JPN":"<color=#ffd34c>施設内の方々にお伝えします。LAKE-13で、残骸の隔離に失敗しました。</color>","ENG":"<color=#ffd34c>Attention, everyone in the facility. Effective immediately, LAKE-13 has failed to quarantine the remains.</color>","TWN":"<color=#ffd34c>設施內的人員請注意，現在播報通知。目前，在LAKE - 13隔離殘骸失敗。</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>대기 중인 병력은 즉시 격리 구역으로 투입해 주시길 바랍니다.</color>","JPN":"<color=#ffd34c>待機中の隊員は、直ちに隔離区域へ向かってください。</color>","ENG":"<color=#ffd34c>All troops on standby must head to the quarantine area immediately.</color>","TWN":"<color=#ffd34c>待命中的兵力請馬上前往隔離區域投入戰鬥。</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>비무장 인원들은</color> <color=#ff3636>격리 구</color><color=#ffd34c>역으로 이동하시어</color> <color=#ff3636>하나가 되</color><color=#ffd34c>길 바랍니다.</color>","JPN":"<color=#ffd34c>非武装者は</color> <color=#ff3636>隔離区域</color><color=#ffd34c>へ移動し、</color> <color=#ff3636>一か所へ集まって</color><color=#ffd34c>ください。</color>","ENG":"<color=#ffd34c>All unarmed personnel should move to the quar</color><color=#ff3636>antine ar</color><color=#ffd34c>ea and beco</color><color=#ff3636>me one imm</color><color=#ffd34c>ediately.</color>","TWN":"<color=#ffd34c>非武裝人員請前往</color><color=#ff3636>隔離區</color><color=#ffd34c>域，</color> <color=#ff3636>合為一體</color><color=#ffd34c>。</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>다시 한 번 안내드립니다. 현재, LAKE-13에서</color> <color=#ff3636>하나가 되겠</color><color=#ffd34c>습니다. 대기 중인 병력은......</color>","JPN":"<color=#ffd34c>もう一度繰り返します。現在、LAKE-13で</color> <color=#ff3636>集まり</color><color=#ffd34c>ます。待機中の隊員は……</color>","ENG":"<color=#ffd34c>Once again. Effective immediately, LAKE-13 has bec</color><color=#ff3636>ome o</color><color=#ffd34c>ne. All troops on standby...</color>","TWN":"<color=#ffd34c>再播報一遍。目前，要在LAKE-13</color><color=#ff3636>合為一體</color><color=#ffd34c>。待命中的兵力……</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L8_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_CHILD","text":{"KOREA":"흑...... 흐윽......","JPN":"ぐすん……ぐす……","ENG":"Hngh... Hnnngh...","TWN":"嗚……嗚嗚……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_CHILD","text":{"KOREA":"저기...... 아, 아무도 없어요?","JPN":"あの……だ、誰かいませんか？","ENG":"Is there... a-anyone there?","TWN":"那個……有、有沒有人啊？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_CHILD","text":{"KOREA":"사무장...... 지, 지부장님......!","JPN":"事務長……し、支部長……！","ENG":"Mr. Chief of Staff? B-Branch Manager?","TWN":"事務長……支、支部長……！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_CHILD","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_CHILD","text":{"KOREA":"나만...... 남은 거야......?","JPN":"私……一人だけなの……？","ENG":"Am I... the only one left?","TWN":"只剩……我一個人了嗎……？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_CHILD","text":{"KOREA":"잡아먹힐 거야...... 여기 있으면 나도 다른 사람들처럼......","JPN":"食べられちゃう……ここにいれば、他の人たちみたいに……","ENG":"I'll get eaten... like the others, if I stay here...","TWN":"會被吃掉的……待在這裡的話，我也會像其他人一樣……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"무기가 통하지 않아! 어서 아가씨를 패닉 룸으로 모셔!","JPN":"武器が通用しない！　早くお嬢様を、セーフルームへお連れしろ！","ENG":"Our weapons are ineffective! Take her to the panic room!","TWN":"武器沒用！快點帶小姐去避難屋！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"본부에 지원 요청을 보냈어! 요원들이 올 때까지 최대한 시간을 벌어야 한다!","JPN":"本部に援護を要請した！　応援が来るまで、できる限り時間を稼げ！","ENG":"I've asked the HQ for reinforcements! We must buy more time until they get here!","TWN":"已經向總部請求支援了！在特工們到達之前，必須儘量爭取時間！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"어서 가십시오, 아가씨!","JPN":"早く逃げてください、お嬢様！","ENG":"Hurry, my lady!","TWN":"快走吧，小姐！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_CHILD","text":{"KOREA":"......아냐. 무서워도 참아야 돼, 엘리자베스.","JPN":"……ううん。怖くても我慢するのよ、エリザベス。","ENG":"No. You must overcome your fears, Elizabeth.","TWN":"……不，就算害怕也要忍耐，伊莉莎白。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_CHILD","text":{"KOREA":"기관장은 언제나 당당하고 여유로워야 한다고...... 버넷 경이 그랬는걸.","JPN":"首長は、常に穏やかで堂々としているべきだって……バーネット卿が言ってたから。","ENG":"The Chief of the Institution must always be proud and confident... That's what Sir Burnett said.","TWN":"機關長在任何時候都要無所畏懼，自信從容才行……伯內特卿說過的。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"성<color=#ff3636>찬이</color> 시작되리라. 탐식<color=#ff3636>자가</color> 굶주렸다.","JPN":"<color=#ff3636>聖餐</color>が始まる。<color=#ff3636>貪食者</color>が飢えている。","ENG":"The <color=#ff3636>f</color>east shall begin. The De<color=#ff3636>vourer</color> hungers.","TWN":"盛<color=#ff3636>宴</color>即將開始，饕<color=#ff3636>餮</color>飢餓了。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>하나</color>에서 여럿으<color=#ff3636>로. 여</color>럿에서 <color=#ff3636>하나</color>로. 정답<color=#ff3636>에 도달</color>하기 위해.","JPN":"<color=#ff3636>1つ</color>から<color=#ff3636>多数</color>へ。<color=#ff3636>多数</color>から<color=#ff3636>1つ</color>ヘ。<color=#ff3636>答え</color>に辿り着くため。","ENG":"From o<color=#ff3636>ne</color> to m<color=#ff3636>any. From m</color>any to <color=#ff3636>one</color>. To <color=#ff3636>reach</color> the answer.","TWN":"<color=#ff3636>從一個</color>到多個<color=#ff3636>，從</color>多個到<color=#ff3636>一個</color>，為了<color=#ff3636>到達</color>正確答案。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_CHILD","text":{"KOREA":"나는...... 너희들이 무섭지 않아!","JPN":"私は……あなたたちを恐れない！","ENG":"I... am not afraid of you!","TWN":"我……我不怕你們！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_CHILD","text":{"KOREA":"귀족으로서 마지막까지 긍지를 지키겠어......!","JPN":"貴族として、最後まで誇りを守るわ……！","ENG":"I will uphold my pride as a noble till the very end!","TWN":"我會堅守貴族的榮譽感到最後……！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"만찬을 <color=#ff3636>열어</color>야 한다. 답<color=#ff3636>을 찾</color>아야 한다.","JPN":"<color=#ff3636>晩餐</color>を開くべきだ。<color=#ff3636>答え</color>を探すべきだ。","ENG":"The feast m<color=#ff3636>ust be he</color>ld. The an<color=#ff3636>swer must b</color>e found.","TWN":"晚宴該<color=#ff3636>開始</color>了，必須要<color=#ff3636>找到答案</color>。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>보다 많</color>은 지식을. 보<color=#ff3636>다 많</color>은 정보를. 보다 <color=#ff3636>많은</color> 진리를.","JPN":"より<color=#ff3636>多く</color>の知識を。より<color=#ff3636>多く</color>の情報を。より<color=#ff3636>多く</color>の真理を。","ENG":"M<color=#ff3636>ore know</color>ledge. M<color=#ff3636>ore info</color>rmation. M<color=#ff3636>ore tr</color>uth.","TWN":"<color=#ff3636>更多的</color>知識，<color=#ff3636>更多的</color>情報，<color=#ff3636>更多的</color>真理。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_CHILD","text":{"KOREA":"읏......!","JPN":"うっ……！","ENG":"Ngh!","TWN":"唔……！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_CHILD","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_CHILD","text":{"KOREA":"전부...... 사라졌어?","JPN":"全部……消えた？","ENG":"It's... all gone?","TWN":"全都……消失了？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"BURNETT_PRYDWEN_NULL_NULL","text":{"KOREA":"무사하셔서 다행입니다. 아가씨. 하마터면 지각할 뻔했군요.","JPN":"ご無事で何よりです、お嬢様。遅刻してしまうところでした。","ENG":"Thank heavens you're alright, my lady. I was almost too late.","TWN":"您平安無事真是太好了，小姐，我差點就來晚了。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_CHILD","text":{"KOREA":"버넷 경! 와 주실 거라고 믿고 있었어요!","JPN":"バーネット卿！　来てくださると信じていました！","ENG":"Sir Burnett! I knew you'd come for me!","TWN":"伯內特卿！我就知道你一定會來的！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BURNETT_PRYDWEN_NULL_NULL","text":{"KOREA":"아가씨가 위험하실 때는 꼭 온다고 약속드렸으니까요.","JPN":"お嬢様が危険に晒された時は、必ず来ると約束したでしょう？","ENG":"I've promised you I'd be there whenever you're in danger, after all.","TWN":"因為我答應過您，在您遇到危險的時候，我一定會出現。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BURNETT_PRYDWEN_NULL_NULL","text":{"KOREA":"말씀드렸죠. 신사는 약속을 어기지 않습니다.","JPN":"以前申し上げたように、紳士は約束を破りません。","ENG":"I told you, didn't I? A true gentleman never breaks his word.","TWN":"我跟您說過吧，紳士不會打破約定的。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BURNETT_PRYDWEN_NULL_NULL","text":{"KOREA":"함께 온 대원들이 시설 안에 퍼진 잔해들을 진압하는 중입니다. 다치신 데는 없습니까?","JPN":"一緒に来た隊員たちが、施設に広まった残骸を鎮圧しています。お怪我はありませんか？","ENG":"The men I brought are neutralizing the contamination throughout the facility as we speak. Are you unhurt?","TWN":"其他隊員們正在鎮壓設施裡的殘骸，您沒受傷吧？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_CHILD","text":{"KOREA":"전 괜찮아요. 시설에 있던 직원 분들이 지켜 주셔서 무사할 수 있었어요.","JPN":"私は大丈夫です。施設にいた職員の方々が守ってくださったおかげで無事でした。","ENG":"I'm fine. The staff here kept me safe.","TWN":"我沒事，多虧設施裡的職員保護我，我才沒有事。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_CHILD","text":{"KOREA":"하지만...... 결국 버넷 경이 오기 전까지 아무것도 못 했어요.","JPN":"でも……結局バーネット卿が来るまで、何もできませんでした。","ENG":"However... I was unable to do anything until you got here.","TWN":"不過……在伯內特卿來之前，我什麼也做不了。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BURNETT_PRYDWEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BURNETT_PRYDWEN_NULL_NULL","text":{"KOREA":"목숨을 구걸하지 않은 것만으로도 훌륭하신 겁니다. 아가씨.","JPN":"命があっただけでも上出来です、お嬢様。","ENG":"You didn't plead for your life. That alone is a remarkable feat, my lady.","TWN":"您沒有求饒就已經很優秀了，小姐。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BURNETT_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐든 처음부터 잘하는 사람은 없습니다. 지금보다 더 잘하려고 하는 사람이 있을 뿐이죠.","JPN":"誰だって初めはぎこちないものです。大事なのは、今より成長するために努力することです。","ENG":"Nobody is perfect from the start. All you can do is try to be a little better tomorrow than today.","TWN":"沒有人從一開始就能做好。只是有些人為了做得比現在更好，而不斷努力而已。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_CHILD","text":{"KOREA":"그러면...... 그렇게 하면 언젠가 저도 훌륭한 기관장이 될 수 있는 걸까요?","JPN":"そうすれば……そうすれば、いつか私も、いい首長になれますか？","ENG":"If I do that... will I become a great Chief one day too?","TWN":"那……那樣的話，總有一天我也能成為優秀的機關長嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BURNETT_PRYDWEN_NULL_NULL","text":{"KOREA":"물론이죠, 아가씨. 약속하겠습니다.","JPN":"もちろんです、お嬢様。約束いたします。","ENG":"Of course, my lady. I give you my word.","TWN":"當然了，小姐，我保證。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BURNETT_PRYDWEN_NULL_NULL","text":{"KOREA":"아가씨께서 훌륭한 기관장이 될 수 있게, 끝까지 옆에서 도와드리겠다고.","JPN":"お嬢様が、いい首長になれるよう。最後までそばでお力添えをすると。","ENG":"I'll assist you by your side until the very end, so that you may become an outstanding Chief of our Institution.","TWN":"在小姐成為優秀的機關長之前，我都會在您身邊幫助您的。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"여어! 데리고 왔네. 혹시 내가 이야기를 방해한 건 아니겠지?","JPN":"おい！　お連れしたぞ。もしかして、邪魔したか？","ENG":"Hey! I've brought him. I hope I'm not interrupting anything.","TWN":"嘿！我把人帶來了。我沒打擾你們說話吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"아닐세, 때맞춰 도착했군, 모건.","JPN":"いや、ちょうどよかった。","ENG":"No, you're just on time, Morgan.","TWN":"沒有，你來得正好，摩根。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"수고 많았어요. 그 원숭이가 버넷 경의 손자인가요?","JPN":"お疲れ様です。その猿が、バーネット卿の孫ですか？","ENG":"Good work. Is that monkey the grandson of Sir Burnett?","TWN":"辛苦了。這隻猴子就是伯內特卿的孫子嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐? 너 지금 나더러 원숭이라고 했냐?","JPN":"は？　お前、俺に向かって猿って言ったか？","ENG":"Huh? Did you just call me monkey?","TWN":"什麼？妳叫我猴子？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그 모습을 보니 원숭이들에게 실례를 해버린 것 같군요, 물벼룩.","JPN":"その様子を見る限り猿以下ですわね、ミジンコ。","ENG":"Oh, I'm sorry. It'd be an insult to monkeys, Mr. Water Flea.","TWN":"看你那樣子，我似乎對猴子們失禮了，水蚤。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이게...... 지금 나랑 싸우자는 거냐?","JPN":"この……ケンカ売ってんのか？","ENG":"Blimey... Are you trying to pick a fight with me?","TWN":"妳……妳是想打架嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"주제 파악을 하세요. 당신이 제가 시비를 걸 만한 상대라도 된다고 생각하나요?","JPN":"身の程を知らないようですわ。私は、あなたがケンカを売ってもいい相手ではありません。","ENG":"Oh, please. What makes you think I'd pick a fight with a brute like you?","TWN":"請有點自知之明。你認為自己是值得我去挑釁的對手嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"버넷 경의 손자가 아니었다면 당신 같은 사람은 저와 이렇게 마주할 기회도 없었을 테니까요.","JPN":"バーネット卿の孫じゃなかったら、私はあなたに会うことすらなかったでしょう。","ENG":"I wouldn't even be talking to someone like you if you weren't Sir Burnett's grandson.","TWN":"你如果不是伯內特卿的孫子，你這種人連像這樣和我見面的機會都沒有。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"......우리 할배를 알아?","JPN":"……俺のじいさんのこと、知ってるのか？","ENG":"Do you know Grandpa?","TWN":"……妳認識我爺爺？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"너 뭐야, 대체?","JPN":"お前、一体何者だ？","ENG":"Who the heck are you?","TWN":"妳究竟是什麼人？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그분은 우리 기관 역대 최고의 요원이셨습니다.","JPN":"あの方は、本機関の歴代最高のエージェントでした。","ENG":"Your grandfather was one of the best agents to have ever worked in the Institution.","TWN":"你爺爺是我們機關有史以來最厲害的特工。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"품위도 학식도 미래도 없어 보이는 당신과는 다르게 말이죠.","JPN":"品も学も未来もなさそうな、あなたとは違って。","ENG":"He was nothing like you, who doesn't seem to have any grace, knowledge, or future.","TWN":"跟你這種沒品位、沒學識、沒未來的三無人士不一樣。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"아, 그러셔? 내가 아는 할배랑은 좀 다른 것 같은데?","JPN":"ああ、そうかよ？　悪いけど、俺の知ってるじいさんとは少し違うな。","ENG":"Oh, really? I don't think we're talking about the same person then.","TWN":"啊，是嗎？跟我認識的爺爺好像不一樣呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"우리 할배는 이런 괴짜들 모임 같은 곳과는 인연이 없는 평범한 사람이라고!","JPN":"俺のじいさんは、こんな変人の集まりみたいな所とは無縁な、平凡な人なんだよ！","ENG":"Grandpa was an average man. He couldn't have gotten involved in any business with you freaks.","TWN":"我爺爺跟你們這種怪人組織可沒半點關係，他就是一個普通人！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"......은퇴 후에 버넷 형님이 좀 소탈한 삶을 즐기시긴 했지.","JPN":"……バーネットが引退後に、凡人のような余生を楽しんだのは確かだ。","ENG":"It's true that Burnett chose to lead a carefree life after retirement.","TWN":"……看來伯內特大哥引退後過得很愜意啊。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"우릴 훈련시킬 땐 구층 지옥에서 올라온 악마 같았는데 말이야.","JPN":"私たちの訓練を受け持った時は、地獄から蘇った悪魔のようだったのにな。","ENG":"He was like a demon from the depth of hell when he was training us.","TWN":"明明訓練我們的時候，像個從九重地獄爬出來的惡魔一樣。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"자네도 근접 전투 배울 때 꽤 시달렸지 않나, 라이언?","JPN":"君も近接戦を教わる時、かなり大変だっただろう？","ENG":"You also had it rough during the CQC drills, didn't you, Ryan?","TWN":"你學習近身戰鬥時，不是也飽受折磨嗎，瑞安？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"악마 같은 게 아니라 악마 그 자체였지.","JPN":"悪魔のようじゃなくて、悪魔そのものだったよ。","ENG":"He wasn't like a demon. He was the demon himself.","TWN":"他不是像惡魔，而是就是惡魔。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"부탁이니까 나쁜 기억 떠올리게 하지 말게, 모건.","JPN":"頼むからトラウマを蘇らせないでくれ、タデウス。","ENG":"Please, Morgan. Don't make me recall terrible memories.","TWN":"算我求你了，別讓我想起痛苦的回憶，摩根。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 당신들 정말 우리 할배와 아는 사이야?","JPN":"な、何だ？　お前ら、本当にじいさんと知り合いか？","ENG":"Huh? Do you really know my Grandpa?","TWN":"什、什麼？你們真的認識我爺爺？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그런데 왜 날 여기로 데려온 거야?","JPN":"なんで俺をここへ連れてきたんだ？","ENG":"Then why did you bring me here?","TWN":"那幹嘛把我帶到這裡來？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"......최근에 벌어진 일련의 사건으로 인해 우리 기관에도 새로운 인력 수급이 필요하다는 판단을 하게 됐습니다.","JPN":"……最近起きた一連の事件によって、この機関にも新しい人材が必要だと判断しました。","ENG":"A series of events that we experienced recently led us to think that the Institution will need to enhance its talent pool.","TWN":"……因為最近發生的一連串事件，讓我覺得我們機關也需要補充新人員了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"당신 같은 물벼룩이 제 높은 기대치의 2%라도 만족시킬 수 있을지는 모르겠지만, 버넷 경의 체면을 생각해서 기회 정도는 드리도록 하죠.","JPN":"あなたのようなミジンコに、私の期待に応えることができるか疑わしいですが、\\nバーネット卿に免じてチャンスを与えましょう。","ENG":"I doubt a water flea like you could live up to my expectations at all, but I'll give you a chance for what Sir Burnett did to the Institution.","TWN":"雖然不知道你這樣的水蚤能不能能達到我期待的2%，但看在伯內特卿的份上，還是給你個機會吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"기회? 뭔 기회?","JPN":"チャンス？　何のチャンスだ？","ENG":"Chance? What chance?","TWN":"機會？什麼機會？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"세상의 진실을 알 기회.","JPN":"世界の真実を知るチャンスです。","ENG":"A chance to embrace the truth.","TWN":"知道世界真相的機會。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"저게...... 뭐야?","JPN":"何だ……あれ？","ENG":"What's... that?","TWN":"那是……什麼？"},"stage":{"bg":"SS_ESPR_03","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"클리포트의 마왕이라고 불리는 신성 침식체.","JPN":"クリフォトの魔王と呼ばれる神聖侵食体。","ENG":"It's a fragment of the Devourer Gha'agsheblah,","TWN":"被稱為逆卡巴拉魔王的神聖侵蝕體。"},"stage":{"bg":"SS_ESPR_03","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"탐식자, 가아그셰블라의 파편입니다.","JPN":"貪食者、ガアグシェブラの破片です。","ENG":"one of the Divine Corrupted Objects known as the Demon Lords of Qliphoth.","TWN":"饕餮，加瓦格舍夫拉的碎片。"},"stage":{"bg":"SS_ESPR_03","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"가아그...... 뭐?","JPN":"ガアグ……何だって？","ENG":"Gha'ag... what?","TWN":"加瓦格……什麼？"},"stage":{"bg":"SS_ESPR_03","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"우리 프리드웬 기관은 오래 전부터 저 마왕을 이곳에 가둬 두기 위해 존재해 왔답니다.","JPN":"プリドウェン機関は、昔からあの魔王をここへ封じ込めるために存在しました。","ENG":"Keeping the Demon Lord sealed here has been at the core of Prydwen Institution's existence since ages ago.","TWN":"我們普利多溫機關從很早以前，就是為了把那個魔王關在這裡而存在的。"},"stage":{"bg":"SS_ESPR_03","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그리고 앞으로 당신이 해야 할 일이기도 하죠.","JPN":"そして、これからあなたがやるべき仕事でもあります。","ENG":"And it will be at the core of your existence from now on.","TWN":"而且這也是你以後要做的事。"},"stage":{"bg":"SS_ESPR_03","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"프리드웬 기관의 비밀 격리 시설, LAKE - 4에 온 것을 환영합니다.","JPN":"プリドウェン機関の秘密隔離施設、LAKE-4へようこそ。","ENG":"Welcome to LAKE-4, Prydwen Institution's top secret quarantine facility,","TWN":"歡迎來到普利多溫機關的秘密隔離設施， LAKE - 4。"},"stage":{"bg":"SS_ESPR_03","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"로이 버넷.","JPN":"ロイ・バーネット。","ENG":"Roy Burnett.","TWN":"羅伊·伯內特。"},"stage":{"bg":"SS_ESPR_03","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};